module RefModule(
    input [15:0] in_value,
    input [15:0] mask_value,
    input [3:0] shift_value,
    input [2:0] op_select,
    output [15:0] out_value
);reg [15:0] obf_temp_value;

always @(*) begin
    case(op_select)
        3'b000: obf_temp_value = in_value & mask_value;
        3'b001: obf_temp_value = in_value | mask_value;
        3'b010: obf_temp_value = in_value ^ mask_value;
        3'b011: obf_temp_value = in_value << shift_value;
        3'b100: obf_temp_value = in_value >> shift_value;
        default: obf_temp_value = in_value;
    endcase
end

assign out_value = obf_temp_value;

endmodule
